new file mode 100644
--- /dev/null
+++ b/src/payments/payment-service.ts
@@ -0,0 +1,24 @@
+type PaymentClient = { charge(input: { amount: number; token: string }): Promise<{ id: string }> };
+
+export class PaymentService {
+  constructor(private readonly client: PaymentClient) {}
+
+  async chargeCustomer(input: { amount: number; token: string }) {
+    if (input.amount <= 0) throw new Error("amount must be positive");
+    return this.client.charge({ amount: input.amount, token: input.token });
+  }
+}
